        var matches = PascalCaseWordPartsRegex().Matches(input);
        if (matches.Count == 0)
        {
            return input;
        }

        // Pre-calculate total length: sum of match lengths + spaces between them
        var totalLength = matches.Count - 1; // spaces
        for (var i = 0; i < matches.Count; i++)
        {
