public static string Dehumanize(this string input)
{
    var words = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    if (words.Length == 0)
    {
        return input;
    }

    if (words.Length == 1)
    {
        return words[0].Pascalize();
    }

    // Use StringBuilder to avoid LINQ enumerator/delegate allocations
    var sb = new System.Text.StringBuilder(input.Length);
    for (var i = 0; i < words.Length; i++)
    {
        sb.Append(words[i].Pascalize());
    }

    return sb.ToString();
}

/// <summary>
/// Converts a string to PascalCase by capitalizing the first letter of each word
/// and removing separators.
/// </summary>
/// <param name="input">The string to pascalize.</param>
/// <returns>A PascalCase representation of the input.</returns>
public static string Pascalize(this string input)
{
    if (string.IsNullOrEmpty(input))
    {
        return input;
    }

    var humanized = input.Humanize();
    return CapitalizeAndRemoveSpaces(humanized);
}

private static string CapitalizeAndRemoveSpaces(string input)
{
    var buffer = new char[input.Length];
    var pos = 0;
    var capitalizeNext = true;

    for (var i = 0; i < input.Length; i++)
    {
        var c = input[i];
        if (c == ' ')
        {
            capitalizeNext = true;
            continue;
        }

        buffer[pos++] = capitalizeNext ? char.ToUpper(c) : c;
        capitalizeNext = false;
    }

    return new string(buffer, 0, pos);
}

